code = """import json, pandas as pd, re

# load full business table
path = var_call_BDpHZDWY0Ef3N4gagdNqyUBb
with open(path, 'r', encoding='utf-8') as f:
    biz_records = json.load(f)

biz = pd.DataFrame(biz_records)
ratings = pd.DataFrame(var_call_jQh2Uqs7IAwMNhMmss3fJqFi)

def parse_hours(val):
    if val is None:
        return None
    if isinstance(val, str):
        if val in ('None','null','NULL',''):
            return None
        try:
            return json.loads(val)
        except Exception:
            return None
    return val

def closes_after_6pm(hours_list):
    if not hours_list:
        return False
    weekdays = {'Monday','Tuesday','Wednesday','Thursday','Friday'}
    for item in hours_list:
        if not (isinstance(item, (list, tuple)) and len(item) == 2):
            continue
        day, span = item
        if day not in weekdays or not span or span == 'Closed':
            continue
        span_s = str(span)
        if 'open 24' in span_s.lower():
            return True
        parts = [p.strip() for p in span_s.split(',')]
        for p in parts:
            m = re.split(r'\u2013|\-|–', p)
            if len(m) != 2:
                continue
            end = m[1].strip()
            mt = re.match(r'^(\d{1,2})(?::(\d{2}))?\s*(AM|PM)?$', end, re.I)
            if not mt:
                continue
            hh = int(mt.group(1))
            mm = int(mt.group(2) or 0)
            ap = (mt.group(3) or '').upper()
            if ap == 'PM' and hh != 12:
                hh += 12
            if ap == 'AM' and hh == 12:
                hh = 0
            end_minutes = hh*60 + mm
            if end_minutes > 18*60:
                return True
    return False

biz['hours_list'] = biz['hours'].apply(parse_hours)
biz['after_6pm_weekday'] = biz['hours_list'].apply(closes_after_6pm)

merged = biz.merge(ratings, on='gmap_id', how='inner')
merged['avg_rating'] = merged['avg_rating'].astype(float)
merged['review_count'] = merged['review_count'].astype(int)

# consider businesses that are open (state contains 'Open' but not 'closed')
state_s = merged['state'].fillna('')
open_mask = state_s.str.contains('Open', case=False, na=False) & (~state_s.str.contains('closed', case=False, na=False))
filtered = merged[open_mask & merged['after_6pm_weekday']]

result_df = filtered.sort_values(['avg_rating','review_count'], ascending=[False, False]).head(5)

out = []
for _, r in result_df.iterrows():
    out.append({'name': r['name'], 'operating_hours': r['hours_list'], 'average_rating': round(float(r['avg_rating']), 4)})

print('__RESULT__:')
print(json.dumps(out))"""

